\begin{lemma}
[Associativity of $\otimes_X$ on line bundles]
  \label{lem:tensorobj_assoc_iso}
  \uses{def:scheme_modules_tensorobj, lem:tensorobj_restrict_iso,
        lem:tensorobj_preserves_locally_trivial}
  Let \(X\) be a scheme and \(L, M, N \in \Scheme.\mathtt{Modules}\,X\) line
  bundles. Then there exists an isomorphism
  \[
    (L \otimes_X M) \otimes_X N
      \;\cong\;
    L \otimes_X (M \otimes_X N)
  \]
  in \(\Scheme.\mathtt{Modules}\,X\); equivalently the proposition
  \(\mathrm{Nonempty}\bigl((L \otimes_X M) \otimes_X N \cong
  L \otimes_X (M \otimes_X N)\bigr)\) holds.
\end{lemma}

\begin{proof}
  \uses{lem:tensorobj_restrict_iso, lem:tensorobj_preserves_locally_trivial}
  Choose a common affine open cover \(\{U_i = \Spec A_i\}\) of \(X\)
  trivialising \(L, M, N\) simultaneously. By
  \cref{lem:tensorobj_preserves_locally_trivial} every tensor product
  occurring on either side is again a line bundle, hence flat, so
  \cref{lem:tensorobj_restrict_iso} applies and both sides restrict to the
  iterated tensor product of \(A_i\)-modules on \(U_i\). There the associator
  \((L_i \otimes_{A_i} M_i) \otimes_{A_i} N_i \cong
  L_i \otimes_{A_i} (M_i \otimes_{A_i} N_i)\) is the standard associativity
  isomorphism of the tensor product of modules over a commutative ring. These
  local isomorphisms agree on overlaps --- naturality of the module
  associator against the restriction-comparison isomorphisms of
  \cref{lem:tensorobj_restrict_iso} --- and therefore glue to a global
  isomorphism. Only the \emph{existence} of the global isomorphism is
  asserted; no compatibility with a pentagon identity is claimed or needed.
\end{proof}

\begin{lemma}
[Unit law for $\otimes_X$ on line bundles]
  \label{lem:tensorobj_unit_iso}
  \uses{def:scheme_modules_tensorobj, lem:tensorobj_restrict_iso}
  Let \(X\) be a scheme and \(L \in \Scheme.\mathtt{Modules}\,X\) a line
  bundle. Then \(\mathcal{O}_X \otimes_X L \cong L\) and
  \(L \otimes_X \mathcal{O}_X \cong L\); equivalently
  \(\mathrm{Nonempty}(\mathcal{O}_X \otimes_X L \cong L)\) holds (and
  symmetrically on the right).
\end{lemma}

\begin{proof}
  \uses{lem:tensorobj_restrict_iso}
  On a trivialising affine cover \(\{U_i = \Spec A_i\}\) of \(L\), restriction
  commutes with \(\otimes_X\) by \cref{lem:tensorobj_restrict_iso}, and the
  structure sheaf restricts to \(A_i\) as an \(A_i\)-module; the unitor
  \(A_i \otimes_{A_i} L_i \cong L_i\) is the standard left-unit isomorphism of
  the tensor product. These local isomorphisms glue to a global isomorphism
  \(\mathcal{O}_X \otimes_X L \cong L\); the right-unit case is identical.
\end{proof}

\begin{lemma}
[Commutativity of $\otimes_X$ on line bundles]
  \label{lem:tensorobj_comm_iso}
  \uses{def:scheme_modules_tensorobj, lem:tensorobj_restrict_iso,
        lem:tensorobj_preserves_locally_trivial}
  Let \(X\) be a scheme and \(L, M \in \Scheme.\mathtt{Modules}\,X\) line
  bundles. Then \(L \otimes_X M \cong M \otimes_X L\); equivalently
  \(\mathrm{Nonempty}(L \otimes_X M \cong M \otimes_X L)\) holds.
\end{lemma}

\begin{proof}
  \uses{lem:tensorobj_restrict_iso, lem:tensorobj_preserves_locally_trivial}
  On a common trivialising affine cover, restriction commutes with
  \(\otimes_X\) (\cref{lem:tensorobj_restrict_iso}); locally the braiding
  \(L_i \otimes_{A_i} M_i \cong M_i \otimes_{A_i} L_i\) is the standard
  symmetry isomorphism of the tensor product of \(A_i\)-modules. The local
  symmetries glue to a global isomorphism.
\end{proof}

